export const docsGuide = {"categories":[{"title":"Getting started","stories":[{"id":"sign-in","title":"Sign in","introHtml":"<p>Org runs your CEO-led agent organizations. Like every OpenApe app it signs you in via DDISA SSO — same passkey, same IdP.</p>\n","steps":[{"title":"Open Org","html":"The start page is the sign-in: enter your email and continue.","shot":"/docs/screenshots/sign-in/01-landing.png"},{"title":"Signed in — your organizations","html":"On first visit the list is empty — each org you create is a virtual company with its own CEO, team, budget and reports.","shot":"/docs/screenshots/sign-in/02-home-empty.png"}]}]},{"title":"Organizations","stories":[{"id":"create-org","title":"Create your first org","introHtml":"<p>An org starts with three things: a name, a vision the CEO will read, and a monthly budget cap the Sanierer enforces.</p>\n","steps":[{"title":"Start a new organization","html":"Click <strong>Create your first org</strong>. The dialog asks for the basics — you can refine the vision and grow the team later.","shot":"/docs/screenshots/create-org/01-dialog.png"},{"title":"Name, vision, budget","html":"The vision is plain prose — the CEO reads it. The monthly budget is the hard cap: above it, the Sanierer stops the CEO from hiring more.","shot":"/docs/screenshots/create-org/02-filled.png"},{"title":"Create","html":"The org page opens: org chart, members, cost dashboard and reports — empty for now, ready for a CEO.","shot":"/docs/screenshots/create-org/03-org-page.png"}]},{"id":"add-ceo","title":"Add a CEO to your org","introHtml":"<p>Your org&#39;s first hire is a CEO — an agent spawned from a pinned recipe and bound to this org. You approve a one-time delegation at your IdP; from then on the CEO runs on your own nest under your account, reading your vision and proposing objectives.</p>\n","steps":[{"title":"Add the CEO seat","html":"Open <strong>Add member</strong>, choose the <strong>CEO</strong> role and name it. Leave the email blank — the org creates a placeholder seat you fill by spawning. (CEO + Sanierer sit at the top of the chart; the Sanierer keeps the CEO honest about cost.)","shot":"/docs/screenshots/add-ceo/01-add-ceo.png"},{"title":"Approve the one-time delegation","html":"Spawning asks your consent <strong>once</strong>. The IdP shows exactly what org may do on your behalf — <em>spawn agents on your troop</em> — as a standing, revocable grant. This is a top-level redirect to your IdP; org never sees your IdP session. Approve it.","shot":"/docs/screenshots/add-ceo/02-consent.png"},{"title":"The CEO is live","html":"Within seconds the CEO is <strong>active</strong> on your nest, with its own <code>…@id.openape.ai</code> identity. It reads your vision live and starts proposing objectives — and you can revoke the delegation at your IdP any time to cut it off.","shot":"/docs/screenshots/add-ceo/03-active.png"}]}]}]}
